INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a1b10900-0000-4000-8000-000000000000','a1b00000-0000-4000-8000-000000000000','確認テスト ─ 会議の設計と運営','quiz',NULL,NULL,NULL,3,2),
  ('a1b20900-0000-4000-8000-000000000000','a1b00000-0000-4000-8000-000000000000','確認テスト ─ 役割分担と権限委譲','quiz',NULL,NULL,NULL,3,4),
  ('a1b30900-0000-4000-8000-000000000000','a1b00000-0000-4000-8000-000000000000','確認テスト ─ 進捗管理','quiz',NULL,NULL,NULL,3,6),
  ('a1b40900-0000-4000-8000-000000000000','a1b00000-0000-4000-8000-000000000000','確認テスト ─ チームのルールづくり','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a1b10900-0000-4000-8000-000000000000','本文が定義する「会議の本質」はどれか。','目的を達成するために、複数人の時間を投資する場である','顔を合わせて関係を深めるための場である','リーダーが指示を伝えるための場である','情報を記録として残すための場である','A',0),
('a1b10900-0000-4000-8000-000000000000','意思決定型のアジェンダに、本文が書けと言う三つはどれか。','目的・参加者・場所','論点・選択肢・決め方','議題・資料・議事録','開始時刻・終了時刻・休憩','B',1),
('a1b10900-0000-4000-8000-000000000000','発散/アイデア型の「絶対のルール」はどれか。','多数決で早く一つに絞る','実現可能な案だけを出す','出ている間は、批判しない','声の大きい人の案を優先する','C',2),
('a1b20900-0000-4000-8000-000000000000','本文が定義する「役割分担」の本質はどれか。','仕事を人数で均等に割り振ることである','仕事に「名前」と「決定権」をつけることである','できる人に重要な仕事を集めることである','作業を細かく分解して指示することである','B',0),
('a1b20900-0000-4000-8000-000000000000','チームの仕事を設計するとき、本文が「多くの主任が抜かしがち」と挙げるのはどの二つか。','棚卸しと割り当て','強みと育成','権限と、重複・空白','名前と作業分配','C',1),
('a1b20900-0000-4000-8000-000000000000','本文が「最悪の手」と呼ぶのはどれか。','できる人に仕事を集めること','見えていない仕事を棚卸しすること','割り当てを一度で固めず組み替えること','責任だけ渡して、権限を渡さないこと','D',2),
('a1b30900-0000-4000-8000-000000000000','本文が定義する「進捗管理」の本質はどれか。','人を追うことではなく、流れを見えるようにすることである','一人ひとりに毎日進捗を報告させることである','リーダーが全員の進捗を頭の中に集めることである','締め切りを厳守させるために追いかけることである','A',0),
('a1b30900-0000-4000-8000-000000000000','本文が「リーダーの本来の仕事」と位置づけるのはどれか。','進捗を回収して集めること','詰まりを見つけて、外すこと','きれいな報告書を作らせること','手順を一手ごとに指示すること','B',1),
('a1b30900-0000-4000-8000-000000000000','進捗を確認するとき、本文が勧める問い方はどれか。','「順調?」と聞く','「まだ終わってないの? いつ終わるの?」と聞く','「あの件、いま、どのあたり? 引っかかってるところある?」と聞く','「なぜ早く言わなかった」と聞く','C',2),
('a1b40900-0000-4000-8000-000000000000','本文が定義する「ルール」の本質はどれか。','やってはいけないことを囲い込む壁である','メンバーが迷わずに動けるようにする、共通の地面である','違反者を罰するための取り締まりの基準である','リーダーの安心を守るための管理装置である','B',0),
('a1b40900-0000-4000-8000-000000000000','本文が挙げる「良いルールが持つ4つの条件」に含まれないものはどれか。','数が、少ない','理由が、共有されている','全員に、同じく適用される','リーダーだけは例外にできる','D',1),
('a1b40900-0000-4000-8000-000000000000','ルールづくりのステップ2で、本文が「最も大事」とし、多くのリーダーが間違えると言うのはどれか。','リーダーが一人で決めて、上から配る','押し付けず、対話で合意する','明文化して、見えるところに置く','念のため先回りでルールを増やす','B',2);
